/** A ProbeRunner that returns a canned ProbeRun (no real process spawn). */
function fakeProbeRunner(run: ProbeRun): ProbeRunner {
  return async () => run;
}

/**
 * A mock fat-station fetch (the QueryFetch seam). It serves /status, /tokenize,
 * /decode-next and /detokenize so runMeshQuery exercises the REAL decode loop
 * against a deterministic node WITHOUT mocking the reply (the runner drives the
 * autoregressive loop itself; only the per-token argmax + the detokenizer text
 * are scripted, exactly as a real fat-station would return them). `decodeMap`
 * maps an input token id -> the node's next-token argmax; `detok` maps the joined
 * out-token-id key -> reply text; `tokenize400` makes /tokenize 400 (smoke-table
 * miss). Records each path hit so tests can assert the wire path used.
 */
function mockFatStation(opts: {
  decodeMap: Record<number, number>;
  detok?: Record<string, string>;
  status?: unknown;
  tokenize?: number[] | { status: number; body: string };
}): { fetch: QueryFetch; paths: string[] } {
  const paths: string[] = [];
  const fetch: QueryFetch = async (url, init) => {
    const u = new URL(url);
    const path = u.pathname;
    paths.push(path);
    const ok = (body: unknown) => ({
      ok: true,
      status: 200,
      text: async () => JSON.stringify(body),
    });
    if (path === '/status') {
      return ok(opts.status ?? { model: 'qwen2.5-0.5b-instruct-mock' });
    }
    if (path === '/tokenize') {
      const t = opts.tokenize;
      if (t && !Array.isArray(t)) {
        return { ok: false, status: t.status, text: async () => t.body };
      }
      return ok({ tokens: Array.isArray(t) ? t : [785, 6722, 315, 9625, 374] });
    }
    if (path === '/decode-next') {
      const inTok = Number(init?.headers?.['X-Token']);
      const next = opts.decodeMap[inTok];
      // A real node always returns SOME argmax; default to a stop token so the
      // loop terminates deterministically if the map is incomplete.
      return ok({ token_id: typeof next === 'number' ? next : 151645 });
    }
    if (path === '/detokenize') {
      const ids = (JSON.parse(init?.body ?? '{}') as { token_ids?: number[] })
        .token_ids ?? [];
      const key = ids.join(',');
      return ok({ text: opts.detok?.[key] ?? '' });
    }
    return { ok: false, status: 404, text: async () => 'not found' };
  };
  return { fetch, paths };
}

// A shared JS-only FlowCodec for decoding the bridge's binary Flow frames.
const flowCodec = FlowCodec.createSync();

// --------------------------------------------------------------------------
// Test harness: mock local monitor + mock relay.
// --------------------------------------------------------------------------

interface MockLocal {
  base: string; // http://127.0.0.1:<port>
  server: Server;
  /** Push one SSE envelope to every open /monitor/stream subscriber. */
  pushFrame: (envelope: unknown) => void;
  /** Subscriber count per scene (to assert subscriptions land). */
  subscribers: () => number;
  /** Captured POST /monitor/control bodies, in order. */
  controlBodies: unknown[];
  /** What POST /monitor/control replies (default ok:true). */
  setControlResponse: (r: unknown) => void;
  setStatus: (s: unknown) => void;
  close: () => Promise<void>;
}

const MOCK_LOCAL_CORS_HEADERS = {
  'access-control-allow-origin': '*',
  'access-control-allow-methods': 'GET,POST,OPTIONS',
  'access-control-allow-headers': 'content-type',
};

function startMockLocal(): Promise<MockLocal> {
  const sseClients = new Set<ServerResponse>();
  const controlBodies: unknown[] = [];
  let scenes: unknown = [{ id: 'skymesh', title: 'Skymesh' }];
  let status: unknown = {
    schemaVersion: 'gnosis.monitor.status.v1',
    activeScene: 'skymesh',
    source: 'demo',
    capture: { running: false },
  };
  let controlResponse: unknown = { ok: true, status: { activeScene: 'skymesh' } };

  const server = createServer((req: IncomingMessage, res: ServerResponse) => {
    const url = (req.url ?? '/').split('?')[0];
    if (req.method === 'OPTIONS') {
      res.writeHead(204, MOCK_LOCAL_CORS_HEADERS);
      res.end();
      return;
    }
    if (req.method === 'POST' && url === '/monitor/control') {
      let body = '';
      req.on('data', (c) => (body += c));
      req.on('end', () => {
        try {
          controlBodies.push(JSON.parse(body));
        } catch {
          controlBodies.push({ __unparsed: body });
        }
        res.writeHead(200, {
          ...MOCK_LOCAL_CORS_HEADERS,
          'content-type': 'application/json',
        });
        res.end(JSON.stringify(controlResponse));
      });
      return;
    }
    if (url === '/monitor/scenes') {
      res.writeHead(200, {
        ...MOCK_LOCAL_CORS_HEADERS,
        'content-type': 'application/json',
      });
      res.end(JSON.stringify(scenes));
      return;
    }
    if (url === '/monitor/status') {
      res.writeHead(200, {
        ...MOCK_LOCAL_CORS_HEADERS,
        'content-type': 'application/json',
      });
      res.end(JSON.stringify(status));
      return;
    }
    if (url === '/monitor/stream') {
      res.writeHead(200, {
        ...MOCK_LOCAL_CORS_HEADERS,
        'content-type': 'text/event-stream',
        'cache-control': 'no-store',
        connection: 'keep-alive',
      });
      res.write(': ping\n\n'); // a heartbeat the parser must ignore
      sseClients.add(res);
      req.on('close', () => sseClients.delete(res));
      return;
    }
    res.writeHead(404, {
      ...MOCK_LOCAL_CORS_HEADERS,
      'content-type': 'application/json',
    });
    res.end(JSON.stringify({ error: 'not_found', path: url }));
  });

  return new Promise<MockLocal>((resolve) => {
    server.listen(0, '127.0.0.1', () => {
      const port = (server.address() as AddressInfo).port;
      resolve({
        base: `http://127.0.0.1:${port}`,
        server,
        pushFrame: (envelope) => {
          const payload = `data: ${JSON.stringify(envelope)}\n\n`;
          for (const c of sseClients) c.write(payload);
        },
        subscribers: () => sseClients.size,
        controlBodies,
        setControlResponse: (r) => {
          controlResponse = r;
        },
        setStatus: (s) => {
          status = s;
        },
        close: () =>
          new Promise<void>((r) => {
            for (const c of sseClients) {
              try {
                c.end();
              } catch {
                /* ignore */
              }
            }
            sseClients.clear();
            server.close(() => r());
          }),
      });
    });
  });
}

interface RelayMessage {
  type: string;
  [k: string]: unknown;
}

interface MockRelay {
  url: string; // ws://127.0.0.1:<port>/monitor/bridge
  wss: WebSocketServer;
  /** Resolves with the next message of `type` the bridge sends UP. */
  nextMessage: (type: string, timeoutMs?: number) => Promise<RelayMessage>;
  /** All UP messages received so far. */
  messages: RelayMessage[];
  /** Send a DOWN message to the connected bridge. */
  sendDown: (msg: unknown) => void;
  /** Token presented by the bridge on the most recent upgrade (?token= or header). */
  lastToken: () => string | undefined;
  /** Query params on the most recent upgrade URL (asserts ?mesh=&node=). */
  lastQuery: () => URLSearchParams | undefined;
  /** Number of bridge connections accepted (asserts reconnect). */
  connectionCount: () => number;
  /** Forcibly drop the current bridge socket (to drive a reconnect). */
  dropCurrent: () => void;
  close: () => Promise<void>;
}

function startMockRelay(): Promise<MockRelay> {
  const messages: RelayMessage[] = [];
  const waiters: { type: string; resolve: (m: RelayMessage) => void }[] = [];
  let current: WsServerSocket | null = null;
  let connectionCount = 0;
  let lastToken: string | undefined;
  let lastQuery: URLSearchParams | undefined;

  const server = createServer();
  const wss = new WebSocketServer({ server, path: '/monitor/bridge' });

  wss.on('connection', (ws: WsServerSocket, req: IncomingMessage) => {
    connectionCount++;
    current = ws;
    const u = new URL(req.url ?? '/', 'http://localhost');
    lastQuery = u.searchParams;
    lastToken =
      u.searchParams.get('token') ??
      req.headers.authorization?.replace(/^Bearer\s+/i, '') ??
      undefined;
    ws.on('message', (data: Buffer) => {
      let msg: RelayMessage;
      try {
        msg = JSON.parse(data.toString('utf8'));
      } catch {
        return;
      }
      messages.push(msg);
      for (let i = waiters.length - 1; i >= 0; i--) {
        if (waiters[i]!.type === msg.type) {
          waiters[i]!.resolve(msg);
          waiters.splice(i, 1);
        }
      }
    });
  });

  return new Promise<MockRelay>((resolve) => {
    server.listen(0, '127.0.0.1', () => {
      const port = (server.address() as AddressInfo).port;
      resolve({
        url: `ws://127.0.0.1:${port}/monitor/bridge`,
        wss,
        messages,
        nextMessage: (type, timeoutMs = 4000) => {
          const existing = messages.find((m) => m.type === type);
          if (existing) return Promise.resolve(existing);
          return new Promise<RelayMessage>((res, rej) => {
            const timer = setTimeout(() => {
              const idx = waiters.findIndex((w) => w.resolve === wrapped);
              if (idx >= 0) waiters.splice(idx, 1);
              rej(new Error(`timeout waiting for UP message type=${type}`));
            }, timeoutMs);
            const wrapped = (m: RelayMessage) => {
              clearTimeout(timer);
              res(m);
            };
            waiters.push({ type, resolve: wrapped });
          });
        },
        sendDown: (msg) => {
          if (current && current.readyState === current.OPEN) {
            current.send(JSON.stringify(msg));
          }
        },
        lastToken: () => lastToken,
        lastQuery: () => lastQuery,
        connectionCount: () => connectionCount,
        dropCurrent: () => {
          if (current) {
            try {
              current.terminate();
            } catch {
              /* ignore */
            }
          }
        },
        close: () =>
          new Promise<void>((r) => {
            wss.close(() => server.close(() => r()));
          }),
      });
    });
  });
}

