// --------------------------------------------------------------------------
// Mock DashRelay aeon-flow room (the RelayRoomDO /.aeon/flow opaque-relay
// contract, handleAeonFlowUpgrade). Accepts the JSON
// {type:"join",room,mode,clientId} -> replies {type:"joined",peerId,...} then
// {type:"flow_ready",...} (both TEXT control frames), then captures each BINARY
// Flow frame the bridge broadcasts. Frames are FlowCodec-decoded so the test can
// assert they are gnosis.monitor.v1 MonitorFlow frames.
// --------------------------------------------------------------------------

interface DecodedFlowFrame {
  streamId: number;
  sequence: number;
  flags: number;
  /** The decoded MonitorFlowFrame (or null when the stream is not MonitorFlow). */
  monitor: { schemaVersion: string; scene: string; kind: string; [k: string]: unknown } | null;
}

interface MockDashRelay {
  /** wss base the bridge dials (ws://127.0.0.1:<port>), no /.aeon/flow. */
  base: string;
  wss: WebSocketServer;
  /** The room name presented on the most recent join. */
  lastRoom: () => string | undefined;
  /** The clientId presented on the most recent join. */
  lastClientId: () => string | undefined;
  /** The mode presented on the most recent join. */
  lastMode: () => string | undefined;
  /** ?room= query on the most recent upgrade URL. */
  lastQueryRoom: () => string | undefined;
  /** Every binary Flow frame the bridge published, FlowCodec-decoded, in order. */
  frames: DecodedFlowFrame[];
  /** Resolves with the next MonitorFlow frame for the given scene. */
  nextMonitorFrame: (scene: string, timeoutMs?: number) => Promise<DecodedFlowFrame>;
  close: () => Promise<void>;
}

function startMockDashRelay(): Promise<MockDashRelay> {
  const frames: DecodedFlowFrame[] = [];
  const waiters: { scene: string; resolve: (f: DecodedFlowFrame) => void }[] = [];
  let lastRoom: string | undefined;
  let lastClientId: string | undefined;
  let lastMode: string | undefined;
  let lastQueryRoom: string | undefined;

  const server = createServer();
  // The LIVE working endpoint: /.aeon/flow (not /relay/sync).
  const wss = new WebSocketServer({ server, path: '/.aeon/flow' });

  wss.on('connection', (ws: WsServerSocket, req: IncomingMessage) => {
    const u = new URL(req.url ?? '/', 'http://localhost');
    lastQueryRoom = u.searchParams.get('room') ?? undefined;
    ws.on('message', (data: Buffer, isBinary: boolean) => {
      // The join is a TEXT JSON frame; everything after is binary Flow frames.
      if (!isBinary) {
        let msg: { type?: string; room?: string; mode?: string; clientId?: string };
        try {
          msg = JSON.parse(data.toString('utf8'));
        } catch {
          return;
        }
        if (msg.type === 'join') {
          lastRoom = msg.room;
          lastClientId = msg.clientId;
          lastMode = msg.mode;
          // joinPeer's {type:"joined"} ack, then handleAeonFlowUpgrade's flow_ready.
          ws.send(JSON.stringify({ type: 'joined', protocol: 'dashrelay-v1', room: msg.room, peerId: 'peer-test', mode: msg.mode, serverSeq: 0 }));
          ws.send(JSON.stringify({ type: 'flow_ready', protocol: 'dashrelay-v1', room: msg.room, peerId: 'peer-test', transport: 'aeon-flow' }));
        }
        return;
      }
      // Binary: a single MonitorFlow Flow frame. Decode + record.
      const bytes = new Uint8Array(data.buffer, data.byteOffset, data.byteLength);
      let decoded: DecodedFlowFrame;
      try {
        const { frame } = flowCodec.decode(bytes);
        let monitor: DecodedFlowFrame['monitor'] = null;
        if (frame.streamId === MONITOR_FLOW_STREAM_ID) {
          monitor = decodeMonitorFlowFrame(frame) as DecodedFlowFrame['monitor'];
        }
        decoded = { streamId: frame.streamId, sequence: frame.sequence, flags: frame.flags, monitor };
      } catch {
        return; // not a decodable Flow frame
      }
      frames.push(decoded);
      const sc = decoded.monitor?.scene;
      for (let i = waiters.length - 1; i >= 0; i--) {
        if (waiters[i]!.scene === sc) {
          waiters[i]!.resolve(decoded);
          waiters.splice(i, 1);
        }
      }
    });
  });

  return new Promise<MockDashRelay>((resolve) => {
    server.listen(0, '127.0.0.1', () => {
      const port = (server.address() as AddressInfo).port;
      resolve({
        base: `ws://127.0.0.1:${port}`,
        wss,
        lastRoom: () => lastRoom,
        lastClientId: () => lastClientId,
        lastMode: () => lastMode,
        lastQueryRoom: () => lastQueryRoom,
        frames,
        nextMonitorFrame: (scene, timeoutMs = 4000) => {
          const existing = frames.find((f) => f.monitor?.scene === scene);
          if (existing) return Promise.resolve(existing);
          return new Promise((res, rej) => {
            const timer = setTimeout(() => {
              const idx = waiters.findIndex((w) => w.resolve === wrapped);
              if (idx >= 0) waiters.splice(idx, 1);
              rej(new Error(`timeout waiting for DashRelay MonitorFlow frame scene=${scene}`));
            }, timeoutMs);
            const wrapped = (f: DecodedFlowFrame) => {
              clearTimeout(timer);
              res(f);
            };
            waiters.push({ scene, resolve: wrapped });
          });
        },
        close: () =>
          new Promise<void>((r) => {
            wss.close(() => server.close(() => r()));
          }),
      });
    });
  });
}

// Track everything to tear down after each test (no leaked sockets/timers).
const cleanups: (() => void | Promise<void>)[] = [];
afterEach(async () => {
  for (const c of cleanups.splice(0).reverse()) await c();
});

// --------------------------------------------------------------------------
// Pure-unit tests (no servers).
// --------------------------------------------------------------------------

describe('argValue / configFromArgv', () => {
  it('reads --name value and falls back to the default', () => {
    expect(argValue(['--relay', 'wss://x'], '--relay', 'def')).toBe('wss://x');
    expect(argValue([], '--relay', 'def')).toBe('def');
    expect(argValue(['--relay'], '--relay', 'def')).toBe('def'); // no value after flag
  });

  it('builds a config from argv + env, splitting scenes and stripping local slash', () => {
    const cfg = configFromArgv(
      ['node', 'x', '--local', 'http://h:1/', '--scenes', 'a, b ,c', '--relay', 'wss://r'],
      { SKYMESH_BRIDGE_TOKEN: 'tok' } as NodeJS.ProcessEnv,
    );
    expect(cfg.relay).toBe('wss://r');
    expect(cfg.local).toBe('http://h:1'); // trailing slash stripped
    expect(cfg.token).toBe('tok'); // from env
    expect(cfg.scenes).toEqual(['a', 'b', 'c']); // trimmed + split
  });

  it('defaults --node-url and reads it from argv / env', () => {
    expect(configFromArgv(['node', 'x'], {} as NodeJS.ProcessEnv).nodeUrl).toBe(
      'http://127.0.0.1:8786',
    );
    expect(
      configFromArgv(['node', 'x', '--node-url', 'http://h:8786/'], {} as NodeJS.ProcessEnv).nodeUrl,
    ).toBe('http://h:8786'); // trailing slash stripped
    expect(
      configFromArgv(['node', 'x'], { SKYMESH_NODE_URL: 'http://env:1' } as NodeJS.ProcessEnv).nodeUrl,
    ).toBe('http://env:1');
  });

  it('exposes the FIXED uplink message types', () => {
    expect([...UPLINK_MESSAGE_TYPES]).toEqual([
      'scenes',
      'status',
      'frame',
      'control-result',
      'preflight-result',
      'query-result',
    ]);
  });

  it('reads --no-relay as a presence flag and defaults mesh/node + dashrelay', () => {
    expect(argFlag(['--no-relay'], '--no-relay')).toBe(true);
    expect(argFlag([], '--no-relay')).toBe(false);

    const def = configFromArgv(['node', 'x'], {} as NodeJS.ProcessEnv);
    expect(def.meshId).toBe(SKYMESH_GLOBAL_MESH_ID);
    expect(typeof def.nodeId).toBe('string');
    expect(def.nodeId.length).toBeGreaterThan(0);
    expect(def.noRelay).toBe(false);
    expect(def.dashrelay).toBe('');

    const cfg = configFromArgv(
      ['node', 'x', '--mesh-id', 'private-x', '--node-id', 'node-7', '--dashrelay', 'wss://relay.example/', '--no-relay'],
      {} as NodeJS.ProcessEnv,
    );
    expect(cfg.meshId).toBe('private-x');
    expect(cfg.nodeId).toBe('node-7');
    expect(cfg.dashrelay).toBe('wss://relay.example'); // trailing slash stripped
    expect(cfg.noRelay).toBe(true);
  });
});

describe('relayUrlWithMesh / dashrelayFlowUrl', () => {
  it('appends ?mesh=&node= to the relay URL, preserving the path', () => {
    const u = new URL(relayUrlWithMesh('wss://skymesh.forkjoin.ai/monitor/bridge', 'skymesh-global', 'node-a'));
    expect(u.pathname).toBe('/monitor/bridge');
    expect(u.searchParams.get('mesh')).toBe('skymesh-global');
    expect(u.searchParams.get('node')).toBe('node-a');
  });

  it('builds the DashRelay aeon-flow room URL', () => {
    expect(dashrelayFlowUrl('wss://dashrelay.com', 'skymesh-global')).toBe(
      'wss://dashrelay.com/.aeon/flow?room=skymesh-global',
    );
    // Trailing slash on the base is tolerated.
    expect(dashrelayFlowUrl('wss://dashrelay.com/', 'private-x')).toBe(
      'wss://dashrelay.com/.aeon/flow?room=private-x',
    );
  });
});

describe('monitorFlowFrameFromEnvelope', () => {
  it('fills width/height/ts defaults and round-trips through FlowCodec + MonitorFlow', () => {
    const frame = monitorFlowFrameFromEnvelope({
      schemaVersion: 'gnosis.monitor.v1',
      scene: 'skymesh',
      kind: 'skymesh',
      vector: { schemaVersion: 'skymesh.v1', stations: [] },
    });
    expect(frame).not.toBeNull();
    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
    const bytes = flowCodec.encode(encodeMonitorFlowFrame(frame!));
    const { frame: decoded } = flowCodec.decode(bytes);
    expect(decoded.streamId).toBe(MONITOR_FLOW_STREAM_ID);
    const mf = decodeMonitorFlowFrame(decoded);
    expect(mf.schemaVersion).toBe('gnosis.monitor.v1');
    expect(mf.scene).toBe('skymesh');
  });

  it('rejects a non-monitor payload', () => {
    expect(monitorFlowFrameFromEnvelope({ schemaVersion: 'other' })).toBeNull();
    expect(monitorFlowFrameFromEnvelope(null)).toBeNull();
    expect(monitorFlowFrameFromEnvelope({ schemaVersion: 'gnosis.monitor.v1', scene: 'x', kind: 'nope' })).toBeNull();
  });
});

describe('PREFLIGHT PARIS gate — argv + parse (pure unit)', () => {
  it('configFromArgv resolves --model / --probe-bin and ~ home', () => {
    const cfg = configFromArgv(
      ['node', 'x', '--model', '~/m.knot', '--probe-bin', '/abs/paris-probe-rknot'],
      {} as NodeJS.ProcessEnv,
    );
    expect(cfg.probeBin).toBe('/abs/paris-probe-rknot');
    expect(cfg.model.startsWith('~')).toBe(false); // ~ expanded to home
    expect(cfg.model.endsWith('/m.knot')).toBe(true);
    // No flags -> sensible defaults (a model path + a prover path).
    const def = configFromArgv(['node', 'x'], {} as NodeJS.ProcessEnv);
    expect(def.model.length).toBeGreaterThan(0);
    expect(def.probeBin.includes('paris-probe-rknot')).toBe(true);
  });

  it('resolveHome expands a leading ~ and leaves absolute paths', () => {
    expect(resolveHome('/abs/path')).toBe('/abs/path');
    expect(resolveHome('~/x').startsWith('~')).toBe(false);
  });

  it('probeArgs builds the FIXED Paris prover argv', () => {
    expect(probeArgs('/m.knot')).toEqual([
      '--dense',
      '/m.knot',
      '--dense-only',
      '--tokens',
      '785,6722,315,9625,374',
      '--expected',
      '12095',
    ]);
  });

  it('parseProbeOutput PASSES on exit 0 + the PASS line, reading rank-0 token+logit', () => {
    const r = parseProbeOutput({ code: 0, stdout: FAKE_PASS_STDOUT, stderr: '' });
    expect(r.pass).toBe(true);
    expect(r.token).toBe(12095);
    expect(r.logit).toBeCloseTo(16.822826, 4);
  });

  it('parseProbeOutput FAILS when the argmax does not match (exit 1)', () => {
    const r = parseProbeOutput({ code: 1, stdout: FAKE_FAIL_STDOUT, stderr: '' });
    expect(r.pass).toBe(false);
    expect(r.token).toBe(7407);
    expect(r.detail).toContain('FAIL');
  });

  it('parseProbeOutput reports a probe error on a spawn failure (code null)', () => {
    const r = parseProbeOutput({ code: null, stdout: '', stderr: 'spawn ENOENT' });
    expect(r.pass).toBe(false);
    expect(r.detail).toContain('probe error');
  });

  it('exposes preflight-result in the FIXED uplink message types', () => {
    expect([...UPLINK_MESSAGE_TYPES]).toContain('preflight-result');
  });
});

describe('SseDataParser', () => {
  it('parses a single data event', () => {
    const p = new SseDataParser();
    expect(p.push('data: {"scene":"skymesh","x":1}\n\n')).toEqual([
      { scene: 'skymesh', x: 1 },
    ]);
  });

  it('buffers a partial event across chunks', () => {
    const p = new SseDataParser();
    expect(p.push('data: {"scene":"a"')).toEqual([]);
    expect(p.push(',"v":2}\n\n')).toEqual([{ scene: 'a', v: 2 }]);
  });

  it('ignores comment heartbeats and emits multiple events in one chunk', () => {
    const p = new SseDataParser();
    const got = p.push(': ping\n\ndata: {"scene":"a"}\n\ndata: {"scene":"b"}\n\n');
    expect(got).toEqual([{ scene: 'a' }, { scene: 'b' }]);
  });

  it('handles CRLF framing', () => {
    const p = new SseDataParser();
    expect(p.push('data: {"scene":"c"}\r\n\r\n')).toEqual([{ scene: 'c' }]);
  });
});

