describe('SkymeshBridge integration', () => {
  it('(a) on open, sends scenes + status UP', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(cfgFor(relay.url, local.base, ['skymesh']));
    cleanups.push(() => bridge.stop());
    bridge.start();

    const scenesMsg = await relay.nextMessage('scenes');
    expect(scenesMsg.type).toBe('scenes');
    expect(scenesMsg.scenes).toEqual([{ id: 'skymesh', title: 'Skymesh' }]);

    const statusMsg = await relay.nextMessage('status');
    expect(statusMsg.type).toBe('status');
    expect((statusMsg.status as { activeScene?: string }).activeScene).toBe('skymesh');

    // The token was presented on the upgrade (query or header).
    expect(relay.lastToken()).toBe('test-token-123');
  });

  it('(b) forwards a local SSE frame UP as {type:"frame",envelope}', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(cfgFor(relay.url, local.base, ['skymesh']));
    cleanups.push(() => bridge.stop());
    bridge.start();

    // Wait for the local SSE subscription to be established before pushing.
    await relay.nextMessage('scenes');
    await waitFor(() => local.subscribers() >= 1, 3000, 'local SSE subscriber');

    const envelope = {
      schemaVersion: 'gnosis.monitor.v1',
      scene: 'skymesh',
      kind: 'skymesh',
      payload: { tick: 7 },
    };
    local.pushFrame(envelope);

    const frameMsg = await relay.nextMessage('frame');
    expect(frameMsg.type).toBe('frame');
    expect(frameMsg.envelope).toEqual(envelope);
    expect(bridge.stats.framesUp).toBeGreaterThanOrEqual(1);
  });

  it('(c) a DOWN control is POSTed to local /monitor/control and a control-result returns UP with the same id', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());
    local.setControlResponse({ ok: true, status: { activeScene: 'mesh' } });

    const bridge = new SkymeshBridge(cfgFor(relay.url, local.base, ['skymesh']));
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes'); // ensure the socket is open

    const id = 'ctl-abc-1';
    relay.sendDown({ type: 'control', id, op: 'select_scene', args: { op: 'select_scene', scene: 'mesh' } });

    const result = await relay.nextMessage('control-result');
    expect(result.type).toBe('control-result');
    expect(result.id).toBe(id);
    expect(result.ok).toBe(true);
    expect((result.status as { activeScene?: string }).activeScene).toBe('mesh');

    // The bridge POSTed the args (which include op) to the local control endpoint.
    expect(local.controlBodies).toHaveLength(1);
    expect(local.controlBodies[0]).toEqual({ op: 'select_scene', scene: 'mesh' });
  });

  it('(c2) a control whose local endpoint fails returns ok:false UP (fail-soft, never throws)', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => relay.close());
    // Close the local monitor so the control POST cannot reach it.
    await local.close();

    const bridge = new SkymeshBridge(cfgFor(relay.url, local.base, ['skymesh']));
    cleanups.push(() => bridge.stop());
    bridge.start();

    // The relay socket still opens even with the local monitor down.
    await waitFor(() => relay.connectionCount() >= 1, 3000, 'relay connection');
    relay.sendDown({ type: 'control', id: 'ctl-fail', op: 'noop', args: { op: 'noop' } });

    const result = await relay.nextMessage('control-result');
    expect(result.id).toBe('ctl-fail');
    expect(result.ok).not.toBe(true);
    expect(typeof result.error).toBe('string');
  });

  it('(d) reconnects after the relay drops the socket', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(cfgFor(relay.url, local.base, ['skymesh']));
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    expect(relay.connectionCount()).toBe(1);

    // Drop the bridge's socket; the bridge must reconnect with backoff and
    // re-send scenes on the new connection.
    relay.dropCurrent();
    await waitFor(() => relay.connectionCount() >= 2, 5000, 'reconnect');

    // After reconnect, scenes is re-sent (the relay cache is refreshed).
    const scenesSeen = relay.messages.filter((m) => m.type === 'scenes').length;
    expect(scenesSeen).toBeGreaterThanOrEqual(2);
  });

  it('(e) carries ?mesh=&node= on the upgrade and sends {type:"hello",nodeId} first', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh'], { meshId: 'mesh-xyz', nodeId: 'node-xyz' }),
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    const hello = await relay.nextMessage('hello');
    expect(hello.type).toBe('hello');
    expect(hello.nodeId).toBe('node-xyz');

    // The GLOBAL PARTYLINE routing rode the upgrade query.
    const q = relay.lastQuery();
    expect(q?.get('mesh')).toBe('mesh-xyz');
    expect(q?.get('node')).toBe('node-xyz');

    // hello precedes scenes (identity first). Wait for scenes to land before
    // checking the ordering (hello is sent before the awaited pushScenes).
    await relay.nextMessage('scenes');
    const helloIdx = relay.messages.findIndex((m) => m.type === 'hello');
    const scenesIdx = relay.messages.findIndex((m) => m.type === 'scenes');
    expect(helloIdx).toBeGreaterThanOrEqual(0);
    expect(scenesIdx).toBeGreaterThan(helloIdx);
  });

  it('(p1) a DOWN preflight runs the prover and replies preflight-result UP with PASS + token 12095', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    // Inject a fake prover that returns the VERIFIED real-output shape. The
    // VERDICT is NOT mocked — parseProbeOutput derives PASS from the real stdout
    // format; only the process spawn is stubbed (the test seam).
    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh']),
      { probeRunner: fakeProbeRunner({ code: 0, stdout: FAKE_PASS_STDOUT, stderr: '' }) },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes'); // socket is open
    // Before any preflight, the node is not admitted.
    const helloBefore = await relay.nextMessage('hello');
    expect(helloBefore.admitted).toBe(false);

    relay.sendDown({ type: 'preflight', id: 'pf-pass-1' });

    const result = await relay.nextMessage('preflight-result');
    expect(result.type).toBe('preflight-result');
    expect(result.id).toBe('pf-pass-1');
    expect(result.pass).toBe(true);
    expect(result.token).toBe(PREFLIGHT_EXPECTED_TOKEN);
    expect(result.text).toBe(PREFLIGHT_EXPECTED_TEXT);
    expect(typeof result.logit).toBe('number');
    expect((result.logit as number)).toBeCloseTo(16.822826, 4);
    expect(typeof result.elapsedMs).toBe('number');
    expect(typeof result.model).toBe('string');

    // A PASS flips the bridge to admitted.
    expect(bridge.stats.admitted).toBe(true);
  });

  it('(p2) a PASS sets admitted in the status sent UP (additive)', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh']),
      { probeRunner: fakeProbeRunner({ code: 0, stdout: FAKE_PASS_STDOUT, stderr: '' }) },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    // The initial status carries admitted:false.
    const statusBefore = await relay.nextMessage('status');
    expect(statusBefore.admitted).toBe(false);

    const before = relay.messages.length;
    relay.sendDown({ type: 'preflight', id: 'pf-pass-2' });
    await relay.nextMessage('preflight-result');

    // After PASS, a fresh status is pushed UP with admitted:true (the preflight
    // re-announces; the change key also folds `admitted`).
    await waitFor(
      () =>
        relay.messages
          .slice(before)
          .some((m) => m.type === 'status' && m.admitted === true),
      3000,
      'status admitted:true after PASS',
    );
  });

  it('(p3) a FAIL replies pass:false with a detail and leaves the node NOT admitted', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh']),
      { probeRunner: fakeProbeRunner({ code: 1, stdout: FAKE_FAIL_STDOUT, stderr: '' }) },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    relay.sendDown({ type: 'preflight', id: 'pf-fail-1' });

    const result = await relay.nextMessage('preflight-result');
    expect(result.id).toBe('pf-fail-1');
    expect(result.pass).toBe(false);
    expect(typeof result.detail).toBe('string');
    expect(bridge.stats.admitted).toBe(false);
  });

  it('(p4) a probe spawn failure replies pass:false with a probe-error detail (never throws)', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh']),
      { probeRunner: fakeProbeRunner({ code: null, stdout: '', stderr: 'spawn ENOENT' }) },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    relay.sendDown({ type: 'preflight', id: 'pf-err-1' });

    const result = await relay.nextMessage('preflight-result');
    expect(result.id).toBe('pf-err-1');
    expect(result.pass).toBe(false);
    expect(String(result.detail)).toContain('probe error');
    expect(bridge.stats.admitted).toBe(false);
  });
});

