// --------------------------------------------------------------------------
// MESH QUERY runner (pure unit — the decode-next path, injected fetch).
// --------------------------------------------------------------------------

describe('runMeshQuery — decode-next path (injected fat-station fetch)', () => {
  // "The capital of France is" -> argmax loop -> " Paris" (the proven gate).
  // Each prompt token's decode returns the next argmax; the final prompt token
  // (374) yields 12095 (" Paris"), and 12095 then yields a stop token so the loop
  // ends after one generated token.
  const PARIS_DECODE: Record<number, number> = {
    785: 0, 6722: 0, 315: 0, 9625: 0, // prompt feed (interim argmaxes ignored)
    374: 12095, // after the last prompt token -> " Paris"
    12095: 151645, // then im_end -> stop
  };

  it('runs the REAL decode loop on raw tokens and returns the decoded reply', async () => {
    const node = mockFatStation({
      decodeMap: PARIS_DECODE,
      detok: { '12095': ' Paris' },
    });
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { tokens: [785, 6722, 315, 9625, 374], maxTokens: 8 },
      node.fetch,
      'qwen2.5-0.5b-instruct.knot',
    );
    expect(out.outTokens).toEqual([12095]);
    expect(out.reply).toBe(' Paris');
    expect(out.promptTokens).toEqual([785, 6722, 315, 9625, 374]);
    expect(out.model).toBe('qwen2.5-0.5b-instruct.knot');
    expect(typeof out.elapsedMs).toBe('number');
    expect(out.detail).toBeUndefined();
    // It used the decode-next + detokenize wire path (NOT /generate).
    expect(node.paths).toContain('/decode-next');
    expect(node.paths).toContain('/detokenize');
    expect(node.paths).not.toContain('/generate');
  });

  it('tokenizes a prompt via the node when no raw tokens are given', async () => {
    const node = mockFatStation({
      decodeMap: PARIS_DECODE,
      detok: { '12095': ' Paris' },
      tokenize: [785, 6722, 315, 9625, 374],
    });
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { prompt: 'The capital of France is', maxTokens: 8 },
      node.fetch,
    );
    expect(node.paths).toContain('/tokenize');
    expect(out.promptTokens).toEqual([785, 6722, 315, 9625, 374]);
    expect(out.reply).toBe(' Paris');
  });

  it('surfaces a smoke-tokenizer 400 as a detail (never throws)', async () => {
    const node = mockFatStation({
      decodeMap: PARIS_DECODE,
      tokenize: { status: 400, body: 'token "supercalifragilistic" not in the smoke table' },
    });
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { prompt: 'supercalifragilistic prose' },
      node.fetch,
    );
    expect(out.reply).toBe('');
    expect(out.outTokens).toEqual([]);
    expect(String(out.detail)).toContain('tokenize failed');
    expect(String(out.detail)).toContain('400');
  });

  it('surfaces a dead node (decode fetch rejects) as a detail (never throws)', async () => {
    const deadFetch: QueryFetch = async () => {
      throw new Error('connect ECONNREFUSED 127.0.0.1:8786');
    };
    const out = await runMeshQuery(
      'http://127.0.0.1:8786',
      { tokens: [785, 6722, 315, 9625, 374] },
      deadFetch,
      'model.knot',
    );
    expect(out.reply).toBe('');
    expect(String(out.detail)).toContain('decode failed');
    expect(out.model).toBe('model.knot');
  });

  it('falls back to the node /status model when no override is given', async () => {
    const node = mockFatStation({
      decodeMap: PARIS_DECODE,
      detok: { '12095': ' Paris' },
      status: { model: 'status-reported-model' },
    });
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { tokens: [785, 6722, 315, 9625, 374], maxTokens: 4 },
      node.fetch,
    );
    expect(out.model).toBe('status-reported-model');
    expect(node.paths).toContain('/status');
  });

  it('defaults maxTokens to QUERY_DEFAULT_MAX_TOKENS and exposes query in the DOWN types', () => {
    expect(QUERY_DEFAULT_MAX_TOKENS).toBe(24);
    expect([...DOWNLINK_MESSAGE_TYPES]).toContain('query');
    expect([...UPLINK_MESSAGE_TYPES]).toContain('query-result');
  });
});

