// --------------------------------------------------------------------------
// GLOBAL ANSWER CACHE (WS-3) — cache-aware mesh-query path.
//
// The bridge uses the SAME injected `queryFetch` seam for BOTH the fat-station
// decode AND the cache HTTP, so these mocks serve /api/v1/cache/* alongside the
// /status, /decode-next, /detokenize fat-station endpoints. The decode is REAL
// against the mocked node; only the per-token argmax + the cache responses are
// scripted (exactly as a real fat-station + real cache would return them).
// --------------------------------------------------------------------------

// "The capital of France is" -> " Paris" (token 12095), then a stop token.
const CACHE_PARIS_TOKENS = [785, 6722, 315, 9625, 374];
const CACHE_PARIS_DECODE: Record<number, number> = {
  785: 0, 6722: 0, 315: 0, 9625: 0,
  374: 12095,
  12095: 151645,
};
const CACHE_MODEL = 'qwen2.5-0.5b-instruct-mock';

/** Build a VERIFIED, gate-passing, signed cache entry for the Paris query. */
function makeValidEntry(
  tokens: number[] = CACHE_PARIS_TOKENS,
  model: string = CACHE_MODEL,
): GlobalAnswerCacheEntry {
  const queryHash = canonicalQueryHash(tokens, SKYMESH_QSPEC_ID);
  const answerTokens = [12095];
  return {
    queryHash,
    queryTokens: tokens,
    model,
    qspecId: SKYMESH_QSPEC_ID,
    answerTokens,
    answerText: ' Paris',
    attestation: {
      gate: 'paris/v1',
      pass: true,
      token: 12095,
      logit: 16.82,
      nodeId: 'cache-seed-node',
      admitted: true,
      sig: signCacheEntryV1(queryHash, answerTokens, 'cache-seed-node', model, SKYMESH_QSPEC_ID),
      attesterDid: 'cache-seed-node',
    },
    ts: Date.now(),
    tier: 'fano7',
  };
}

/**
 * A combined cache + fat-station QueryFetch. `lookupEntry` (when set) is the
 * entry GET .../cache/lookup returns as a hit; null = a miss. `cacheUnreachable`
 * makes every /api/v1/cache/* fetch throw (the graceful-degrade path). Records
 * each path hit + every PUT body so tests assert the wire path + the stored
 * entry. The fat-station side mirrors mockFatStation.
 */
function mockCacheAndNode(opts: {
  lookupEntry?: GlobalAnswerCacheEntry | null;
  cacheUnreachable?: boolean;
}): { fetch: QueryFetch; paths: string[]; puts: GlobalAnswerCacheEntry[] } {
  const paths: string[] = [];
  const puts: GlobalAnswerCacheEntry[] = [];
  const fetch: QueryFetch = async (url, init) => {
    const u = new URL(url);
    const path = u.pathname;
    paths.push(path);
    const ok = (body: unknown) => ({
      ok: true,
      status: 200,
      text: async () => JSON.stringify(body),
    });
    // ── cache endpoints ──
    if (path === '/api/v1/cache/lookup') {
      if (opts.cacheUnreachable) throw new Error('connect ECONNREFUSED cache');
      const entry = opts.lookupEntry ?? null;
      return ok(entry ? { hit: true, entry } : { hit: false });
    }
    if (path === '/api/v1/cache/put') {
      if (opts.cacheUnreachable) throw new Error('connect ECONNREFUSED cache');
      try {
        puts.push(JSON.parse(init?.body ?? '{}') as GlobalAnswerCacheEntry);
      } catch {
        /* ignore */
      }
      return ok({ ok: true, tier: 'monster196884' });
    }
    // ── fat-station endpoints ──
    if (path === '/status') return ok({ model: CACHE_MODEL });
    if (path === '/decode-next') {
      const inTok = Number(init?.headers?.['X-Token']);
      const next = CACHE_PARIS_DECODE[inTok];
      return ok({ token_id: typeof next === 'number' ? next : 151645 });
    }
    if (path === '/detokenize') {
      const ids = (JSON.parse(init?.body ?? '{}') as { token_ids?: number[] }).token_ids ?? [];
      return ok({ text: ids.join(',') === '12095' ? ' Paris' : '' });
    }
    return { ok: false, status: 404, text: async () => 'not found' };
  };
  return { fetch, paths, puts };
}

describe('GLOBAL ANSWER CACHE — key + sign + verify (pure unit)', () => {
  it('canonicalQueryHash is deterministic and token-sensitive (fp48, 12 hex); MODEL-AGNOSTIC', () => {
    const a = canonicalQueryHash(CACHE_PARIS_TOKENS, SKYMESH_QSPEC_ID);
    const a2 = canonicalQueryHash(CACHE_PARIS_TOKENS, SKYMESH_QSPEC_ID);
    expect(a).toBe(a2);
    expect(a).toMatch(/^[0-9a-f]{12}$/);
    // one differing prompt token changes the key
    const b = canonicalQueryHash([785, 6722, 315, 9625, 375], SKYMESH_QSPEC_ID);
    expect(b).not.toBe(a);
    // model is NOT in the key: the key is computed over (tokens, qspec) only, so
    // a different provenance model is the SAME key (the model-agnostic feature).
    const c = canonicalQueryHash(CACHE_PARIS_TOKENS, SKYMESH_QSPEC_ID);
    expect(c).toBe(a);
  });

  it('verifyCacheEntry accepts a pass+admitted+signed identity-matching entry', () => {
    const entry = makeValidEntry();
    const hash = canonicalQueryHash(CACHE_PARIS_TOKENS, SKYMESH_QSPEC_ID);
    expect(verifyCacheEntry(entry, hash, CACHE_PARIS_TOKENS)).toBe(true);
  });

  it('verifyCacheEntry rejects non-pass / non-admitted / unsigned / mismatch', () => {
    const hash = canonicalQueryHash(CACHE_PARIS_TOKENS, SKYMESH_QSPEC_ID);
    const notPass = makeValidEntry();
    notPass.attestation.pass = false;
    expect(verifyCacheEntry(notPass, hash, CACHE_PARIS_TOKENS)).toBe(false);
    const notAdmitted = makeValidEntry();
    notAdmitted.attestation.admitted = false;
    expect(verifyCacheEntry(notAdmitted, hash, CACHE_PARIS_TOKENS)).toBe(false);
    const unsigned = makeValidEntry();
    unsigned.attestation.sig = '';
    expect(verifyCacheEntry(unsigned, hash, CACHE_PARIS_TOKENS)).toBe(false);
    // request tokens that do not match the stored entry -> rejected (fp48 guard)
    const ok = makeValidEntry();
    const otherHash = canonicalQueryHash([785], SKYMESH_QSPEC_ID);
    expect(verifyCacheEntry(ok, otherHash, [785])).toBe(false);
  });
});

describe('runMeshQuery — cache-aware (lookup/store hooks)', () => {
  it('(c-hit) a VERIFIED cache hit is served WITHOUT inference (cached:true)', async () => {
    const node = mockCacheAndNode({ lookupEntry: makeValidEntry() });
    let storeCalled = false;
    const hooks: MeshQueryCacheHooks = {
      lookup: async (tokens, model) => {
        const entry = makeValidEntry(tokens, model);
        const hash = canonicalQueryHash(tokens, SKYMESH_QSPEC_ID);
        if (!verifyCacheEntry(entry, hash, tokens)) return null;
        return { outTokens: entry.answerTokens, reply: entry.answerText, tier: entry.tier };
      },
      store: async () => {
        storeCalled = true;
      },
    };
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { tokens: CACHE_PARIS_TOKENS, maxTokens: 8 },
      node.fetch,
      CACHE_MODEL,
      hooks,
    );
    expect(out.cached).toBe(true);
    expect(out.cacheTier).toBe('fano7');
    expect(out.reply).toBe(' Paris');
    expect(out.outTokens).toEqual([12095]);
    // NO inference happened: the decode-next / detokenize wire path was untouched.
    expect(node.paths).not.toContain('/decode-next');
    expect(node.paths).not.toContain('/detokenize');
    expect(storeCalled).toBe(false);
  });

  it('(c-miss) a miss runs inference and calls store with the real answer (cached:false)', async () => {
    const node = mockCacheAndNode({ lookupEntry: null });
    const stored: Array<{ tokens: number[]; out: number[]; reply: string; model: string }> = [];
    const hooks: MeshQueryCacheHooks = {
      lookup: async () => null, // miss
      store: async (tokens, out, reply, model) => {
        stored.push({ tokens, out, reply, model });
      },
    };
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { tokens: CACHE_PARIS_TOKENS, maxTokens: 8 },
      node.fetch,
      CACHE_MODEL,
      hooks,
    );
    expect(out.cached).toBe(false);
    expect(out.outTokens).toEqual([12095]);
    expect(out.reply).toBe(' Paris');
    // inference DID run
    expect(node.paths).toContain('/decode-next');
    // store offered the real answer
    expect(stored).toHaveLength(1);
    expect(stored[0]!.out).toEqual([12095]);
    expect(stored[0]!.tokens).toEqual(CACHE_PARIS_TOKENS);
  });

  it('(c-graceful) an unreachable cache (lookup returns null) falls through to inference', async () => {
    const node = mockCacheAndNode({ lookupEntry: null });
    const hooks: MeshQueryCacheHooks = {
      lookup: async () => null, // simulates an unreachable cache (graceful null)
      store: async () => {
        /* unreachable cache also no-ops store */
      },
    };
    const out = await runMeshQuery(
      'http://127.0.0.1:9999',
      { tokens: CACHE_PARIS_TOKENS, maxTokens: 8 },
      node.fetch,
      CACHE_MODEL,
      hooks,
    );
    expect(out.cached).toBe(false);
    expect(out.reply).toBe(' Paris');
    expect(node.paths).toContain('/decode-next');
  });
});

describe('SkymeshBridge mesh query — cache-aware', () => {
  it('(cb-hit) a DOWN query served from the cache replies cached:true with NO inference', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const cache = mockCacheAndNode({ lookupEntry: makeValidEntry() });
    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh'], {
        nodeUrl: 'http://127.0.0.1:9999',
        model: CACHE_MODEL,
        cacheUrl: 'https://cache.test',
      }),
      { queryFetch: cache.fetch },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    relay.sendDown({ type: 'query', id: 'q-hit', tokens: CACHE_PARIS_TOKENS, maxTokens: 8 });

    const result = await relay.nextMessage('query-result');
    expect(result.id).toBe('q-hit');
    expect(result.cached).toBe(true);
    expect(result.reply).toBe(' Paris');
    expect(result.outTokens).toEqual([12095]);
    // The cache was looked up; NO decode happened.
    expect(cache.paths).toContain('/api/v1/cache/lookup');
    expect(cache.paths).not.toContain('/decode-next');
    expect(cache.puts).toHaveLength(0);
  });

  it('(cb-miss-put) an admitted node on a cache MISS runs inference and PUTs a pass+admitted+signed entry', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const cache = mockCacheAndNode({ lookupEntry: null });
    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh'], {
        nodeUrl: 'http://127.0.0.1:9999',
        model: CACHE_MODEL,
        cacheUrl: 'https://cache.test',
      }),
      {
        queryFetch: cache.fetch,
        probeRunner: fakeProbeRunner({ code: 0, stdout: FAKE_PASS_STDOUT, stderr: '' }),
      },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    // Admit the node first (a PASS preflight) so it is allowed to seed the cache.
    relay.sendDown({ type: 'preflight', id: 'pf-admit' });
    await relay.nextMessage('preflight-result');
    expect(bridge.stats.admitted).toBe(true);

    relay.sendDown({ type: 'query', id: 'q-miss', tokens: CACHE_PARIS_TOKENS, maxTokens: 8 });
    const result = await relay.nextMessage('query-result');
    expect(result.id).toBe('q-miss');
    expect(result.cached).toBe(false);
    expect(result.reply).toBe(' Paris');
    expect(cache.paths).toContain('/decode-next'); // inference ran
    // Wait for the best-effort PUT to land (it is awaited inside runMeshQuery's
    // store hook, so by the time the result is UP the PUT has been attempted).
    await waitFor(() => cache.puts.length > 0, 2000, 'cache PUT');
    expect(cache.puts).toHaveLength(1);
    const put = cache.puts[0]!;
    expect(put.attestation.pass).toBe(true);
    expect(put.attestation.admitted).toBe(true);
    expect(put.attestation.sig.length).toBeGreaterThan(0);
    expect(put.answerTokens).toEqual([12095]);
    expect(put.queryTokens).toEqual(CACHE_PARIS_TOKENS);
    expect(put.qspecId).toBe(SKYMESH_QSPEC_ID);
    // The stored entry's identity re-hashes to its queryHash (verifiable).
    expect(put.queryHash).toBe(
      canonicalQueryHash(CACHE_PARIS_TOKENS, SKYMESH_QSPEC_ID),
    );
  });

  it('(cb-not-admitted) a NOT-admitted node on a cache MISS runs inference but NEVER PUTs', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const cache = mockCacheAndNode({ lookupEntry: null });
    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh'], {
        nodeUrl: 'http://127.0.0.1:9999',
        model: CACHE_MODEL,
        cacheUrl: 'https://cache.test',
      }),
      { queryFetch: cache.fetch }, // no preflight -> never admitted
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    expect(bridge.stats.admitted).toBe(false);

    relay.sendDown({ type: 'query', id: 'q-noadmit', tokens: CACHE_PARIS_TOKENS, maxTokens: 8 });
    const result = await relay.nextMessage('query-result');
    expect(result.id).toBe('q-noadmit');
    expect(result.cached).toBe(false);
    expect(result.reply).toBe(' Paris');
    expect(cache.paths).toContain('/decode-next'); // inference ran
    // Give any (incorrect) PUT a chance to land, then assert NONE did.
    await new Promise((r) => setTimeout(r, 150));
    expect(cache.puts).toHaveLength(0);
    expect(cache.paths).not.toContain('/api/v1/cache/put');
  });

  it('(cb-unreachable) an unreachable cache degrades gracefully to inference (cached:false)', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const cache = mockCacheAndNode({ cacheUnreachable: true });
    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh'], {
        nodeUrl: 'http://127.0.0.1:9999',
        model: CACHE_MODEL,
        cacheUrl: 'https://cache.test',
      }),
      {
        queryFetch: cache.fetch,
        probeRunner: fakeProbeRunner({ code: 0, stdout: FAKE_PASS_STDOUT, stderr: '' }),
      },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    relay.sendDown({ type: 'preflight', id: 'pf-admit-2' });
    await relay.nextMessage('preflight-result');

    relay.sendDown({ type: 'query', id: 'q-unreach', tokens: CACHE_PARIS_TOKENS, maxTokens: 8 });
    const result = await relay.nextMessage('query-result');
    expect(result.id).toBe('q-unreach');
    // cache throws on lookup -> falls through to a real decode; the query never breaks.
    expect(result.cached).toBe(false);
    expect(result.reply).toBe(' Paris');
    expect(cache.paths).toContain('/decode-next');
  });

  it('(cb-off) with the cache OFF (no cacheUrl) the result omits the cached flag entirely', async () => {
    const local = await startMockLocal();
    const relay = await startMockRelay();
    cleanups.push(() => local.close(), () => relay.close());

    const cache = mockCacheAndNode({ lookupEntry: makeValidEntry() });
    const bridge = new SkymeshBridge(
      cfgFor(relay.url, local.base, ['skymesh'], {
        nodeUrl: 'http://127.0.0.1:9999',
        model: CACHE_MODEL,
        cacheUrl: '', // cache OFF
      }),
      { queryFetch: cache.fetch },
    );
    cleanups.push(() => bridge.stop());
    bridge.start();

    await relay.nextMessage('scenes');
    relay.sendDown({ type: 'query', id: 'q-off', tokens: CACHE_PARIS_TOKENS, maxTokens: 8 });
    const result = await relay.nextMessage('query-result');
    expect(result.id).toBe('q-off');
    // cache OFF: never touched, and `cached` is omitted (additive only).
    expect('cached' in result).toBe(false);
    expect(cache.paths).not.toContain('/api/v1/cache/lookup');
    expect(cache.paths).toContain('/decode-next');
  });
});

// --------------------------------------------------------------------------
// Small polling helper (no fake timers; real sockets).
// --------------------------------------------------------------------------

async function waitFor(
  cond: () => boolean,
  timeoutMs: number,
  label: string,
): Promise<void> {
  const start = Date.now();
  while (!cond()) {
    if (Date.now() - start > timeoutMs) throw new Error(`timeout waiting for ${label}`);
    await new Promise((r) => setTimeout(r, 20));
  }
}
